function out = fSpotAnalysisV02(x,y,img,thre)%% Perform spot analysis, peak and mean location,% FWHM for lineout through mean of img>thre% 1/e^2 width for lineout through mean of img>thre% std for integrated array.%% out = fSpotAnalysisV02(x,y,img,thre)%% x,y: axis information (x axis)% img: image%% out: output array%       1-2: peak location (x,y)%       3-4: mean location (x,y)%       5-6: mean with threshold (x,y)%       7-8: FWHM (x,y, from inside)%       9-10: std (standard deviation, x,y)%       11-12: 1/e^2 (x,y)%% Revision history% Copyright Kei Nakamura% 2011/10/28 ver.1: created% 2013/11/5 ver.1b: clean up% 2018/8/23 ver.2: added threshold and 1/e^2%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body% get peak location[~,rows] = max(img);[~,maxXi] = max(max(img)); % max x indexmaxYi = rows(maxXi);            % max y indexpeakX = x(maxXi);peakY = y(maxYi);% get thresholded mean locationimg2 = img.*(img>thre);[~,meanXT] = fGetRmsV01(x,sum(img2));[~,meanYT] = fGetRmsV01(y,sum(img2,2)');[~,meanXTi] = min(abs(x-meanXT));    % get index for meanXT[~,meanYTi] = min(abs(y-meanYT));    % get index for meanXT% get fwhm (lineout along threholded mean)fwhmX = fGetFwhmV04(x,img(meanYTi,:));fwhmY = fGetFwhmV04(y,img(:,meanXTi));% get e2widthe2X = fGetE2Width(x,img(meanYTi,:));e2Y = fGetE2Width(y,img(:,meanXTi));% get rms (sum)[stdX,meanX] = fGetRmsV01(x,sum(img));[stdY,meanY] = fGetRmsV01(y,sum(img,2)');out(1:2) = [peakX,peakY]; % peak locationout(3:4) = [meanX,meanY]; % mean locationout(5:6) = [meanXT,meanYT]; % thre-mean locationout(7:8) = [fwhmX,fwhmY]; % peak locationout(9:10) = [stdX,stdY]; % peak locationout(11:12) = [e2X,e2Y]; % peak location
